import{_ as t,o,c as a,a0 as d}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Naming Refactor Plan — Clarity Between Shared, Anime, and Movies & TV","description":"","frontmatter":{},"headers":[],"relativePath":"PLAN_NAMING_REFACTOR.md","filePath":"PLAN_NAMING_REFACTOR.md"}'),s={name:"PLAN_NAMING_REFACTOR.md"};function i(n,e,r,c,l,h){return o(),a("div",null,[...e[0]||(e[0]=[d(`<h1 id="naming-refactor-plan-—-clarity-between-shared-anime-and-movies-tv" tabindex="-1">Naming Refactor Plan — Clarity Between Shared, Anime, and Movies &amp; TV <a class="header-anchor" href="#naming-refactor-plan-—-clarity-between-shared-anime-and-movies-tv" aria-label="Permalink to &quot;Naming Refactor Plan — Clarity Between Shared, Anime, and Movies &amp; TV&quot;">​</a></h1><blockquote><p><strong>Status:</strong> Phase A, B, C &amp; D Complete <strong>Created:</strong> 2026-06-23<br><strong>Updated:</strong> 2026-06-24<br><strong>Purpose:</strong> Fix confusing names that make it hard to tell what belongs to anime, what belongs to movies, and what is shared between both.</p></blockquote><hr><h2 id="the-problem-simple-explanation" tabindex="-1">The Problem (Simple Explanation) <a class="header-anchor" href="#the-problem-simple-explanation" aria-label="Permalink to &quot;The Problem (Simple Explanation)&quot;">​</a></h2><p>Right now, the app has <strong>one screen layout</strong> (one HTML page) that serves <strong>two different modes</strong>:</p><ul><li><strong>Anime mode</strong> — browsing anime content</li><li><strong>Movies &amp; TV mode</strong> — browsing movies and TV shows</li></ul><p>The problem is that <strong>everything is named &quot;home_&quot;</strong> regardless of whether it&#39;s:</p><ol><li>A <strong>shared piece</strong> used by both modes (like the top navigation bar)</li><li>Something <strong>only for anime</strong> (like &quot;Recently Updated&quot; anime lists)</li><li>Something <strong>only for movies</strong> (like TMDB trending movies)</li></ol><p>This makes it confusing to understand what belongs where.</p><p><strong>Examples of the confusion:</strong></p><table tabindex="0"><thead><tr><th>Current Name</th><th>What It Actually Is</th></tr></thead><tbody><tr><td><code>home_header</code></td><td>The top navigation bar — shared by BOTH modes</td></tr><tr><td><code>home.js</code> (module 19)</td><td>The main controller — handles BOTH modes</td></tr><tr><td><code>fmovies.js</code> (module 21)</td><td>Movies &amp; TV specific logic</td></tr><tr><td><code>home_page</code></td><td>The main content area — could be anime OR movies depending on mode</td></tr><tr><td><code>home_pagemovies</code></td><td>Movies-only page — clear ✅</td></tr><tr><td><code>home_homepage</code></td><td>The &quot;Home&quot; button — shared by both</td></tr></tbody></table><p>There&#39;s no clear naming pattern that tells you: &quot;this is shared&quot;, &quot;this is anime-only&quot;, or &quot;this is movies-only.&quot;</p><hr><h2 id="the-goal" tabindex="-1">The Goal <a class="header-anchor" href="#the-goal" aria-label="Permalink to &quot;The Goal&quot;">​</a></h2><p>After this refactor, anyone reading the code should immediately know:</p><ul><li><strong>&quot;app_&quot;</strong> or <strong>&quot;shell_&quot;</strong> prefix = shared across all modes</li><li><strong>&quot;anime_&quot;</strong> prefix = anime-specific</li><li><strong>&quot;movies_&quot;</strong> or <strong>&quot;fmovies_&quot;</strong> prefix = Movies &amp; TV specific</li></ul><hr><h2 id="proposed-naming-convention" tabindex="-1">Proposed Naming Convention <a class="header-anchor" href="#proposed-naming-convention" aria-label="Permalink to &quot;Proposed Naming Convention&quot;">​</a></h2><h3 id="tier-1-shared-ui-used-by-both-modes" tabindex="-1">Tier 1: Shared UI (Used By Both Modes) <a class="header-anchor" href="#tier-1-shared-ui-used-by-both-modes" aria-label="Permalink to &quot;Tier 1: Shared UI (Used By Both Modes)&quot;">​</a></h3><p>These are the &quot;skeleton&quot; pieces that exist regardless of whether you&#39;re watching anime or movies.</p><table tabindex="0"><thead><tr><th>Current Name</th><th>Proposed Name</th><th>What It Is</th></tr></thead><tbody><tr><td><code>home_header</code></td><td><code>app_header</code></td><td>The top navigation bar</td></tr><tr><td><code>home_header_banner</code></td><td><code>app_header_banner</code></td><td>The banner area inside the header</td></tr><tr><td><code>home_time</code></td><td><code>app_clock</code></td><td>The clock display</td></tr><tr><td><code>home_search</code></td><td><code>app_nav_search</code></td><td>Search button</td></tr><tr><td><code>home_homepage</code></td><td><code>app_nav_home</code></td><td>Home button</td></tr><tr><td><code>home_mylist</code></td><td><code>app_nav_mylist</code></td><td>My List button</td></tr><tr><td><code>home_settings</code></td><td><code>app_nav_settings</code></td><td>Settings button</td></tr><tr><td><code>home_logo</code></td><td><code>app_nav_menu</code></td><td>Menu/Logo button</td></tr><tr><td><code>home_scroll</code></td><td><code>app_scroll</code></td><td>The scrollable content area</td></tr><tr><td><code>home_scroll_mask</code></td><td><code>app_scroll_mask</code></td><td>Scroll container wrapper</td></tr><tr><td><code>home_slide</code></td><td><code>app_slideshow</code></td><td>The top banner slideshow</td></tr></tbody></table><h3 id="tier-2-anime-specific" tabindex="-1">Tier 2: Anime-Specific <a class="header-anchor" href="#tier-2-anime-specific" aria-label="Permalink to &quot;Tier 2: Anime-Specific&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Current Name</th><th>Proposed Name</th><th>What It Is</th></tr></thead><tbody><tr><td><code>home_schedule</code></td><td><code>anime_nav_schedule</code></td><td>Anime airing schedule button</td></tr><tr><td><code>home_pageschedule</code></td><td><code>anime_page_schedule</code></td><td>Anime schedule page</td></tr><tr><td>(sections in init_homepage for anime)</td><td><code>anime_section_*</code></td><td>Anime-specific content sections</td></tr></tbody></table><h3 id="tier-3-movies-tv-specific" tabindex="-1">Tier 3: Movies &amp; TV Specific <a class="header-anchor" href="#tier-3-movies-tv-specific" aria-label="Permalink to &quot;Tier 3: Movies &amp; TV Specific&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Current Name</th><th>Proposed Name</th><th>What It Is</th></tr></thead><tbody><tr><td><code>home_movies</code></td><td><code>movies_nav_movies</code></td><td>Movies tab button</td></tr><tr><td><code>home_tvshows</code></td><td><code>movies_nav_tvshows</code></td><td>TV Shows tab button</td></tr><tr><td><code>home_browse</code></td><td><code>movies_nav_browse</code></td><td>Browse tab button</td></tr><tr><td><code>home_pagemovies</code></td><td><code>movies_page_movies</code></td><td>Movies page</td></tr><tr><td><code>home_pagetvshows</code></td><td><code>movies_page_tvshows</code></td><td>TV Shows page</td></tr><tr><td><code>home_pagebrowse</code></td><td><code>movies_page_browse</code></td><td>Browse/Discovery page</td></tr></tbody></table><h3 id="tier-4-file-names" tabindex="-1">Tier 4: File Names <a class="header-anchor" href="#tier-4-file-names" aria-label="Permalink to &quot;Tier 4: File Names&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Current Name</th><th>Proposed Name</th><th>Reason</th></tr></thead><tbody><tr><td><code>19-home.js</code></td><td><code>19-app-shell.js</code></td><td>It controls the shared app shell (navigation, settings, sidebar) — not just &quot;home&quot;</td></tr><tr><td><code>21-fmovies.js</code></td><td><code>21-movies-source.js</code></td><td>Clearer that this is the Movies &amp; TV data source</td></tr><tr><td>(no file)</td><td>Consider <code>20-anime-home.js</code> in the future</td><td>Anime-specific home page logic (currently mixed into 19-home.js)</td></tr></tbody></table><hr><h2 id="what-changes" tabindex="-1">What Changes <a class="header-anchor" href="#what-changes" aria-label="Permalink to &quot;What Changes&quot;">​</a></h2><h3 id="phase-a-rename-html-element-ids-biggest-impact" tabindex="-1">Phase A: Rename HTML Element IDs (Biggest Impact) <a class="header-anchor" href="#phase-a-rename-html-element-ids-biggest-impact" aria-label="Permalink to &quot;Phase A: Rename HTML Element IDs (Biggest Impact)&quot;">​</a></h3><p>The <code>&lt;div id=&quot;home_header&quot;&gt;</code> in <code>main.html</code> becomes <code>&lt;div id=&quot;app_header&quot;&gt;</code>.</p><p><strong>All CSS files</strong> that reference <code>#home_header</code> need updating:</p><ul><li><code>fp.css</code> (portrait)</li><li><code>p.css</code> (portrait)</li><li><code>fm.css</code> (landscape for movies)</li><li>Any other CSS files</li></ul><p><strong>All JS files</strong> that reference <code>$(&#39;home_header&#39;)</code> or <code>home_header</code> need updating:</p><ul><li><code>19-home.js</code></li><li><code>18-playback.js</code></li></ul><h3 id="phase-b-rename-the-javascript-object" tabindex="-1">Phase B: Rename the JavaScript Object <a class="header-anchor" href="#phase-b-rename-the-javascript-object" aria-label="Permalink to &quot;Phase B: Rename the JavaScript Object&quot;">​</a></h3><p>The <code>home</code> object in <code>19-home.js</code> could be renamed to <code>app</code> or <code>shell</code> since it&#39;s the main controller for both modes. The <code>home_header</code> property becomes <code>app.header</code>.</p><blockquote><p>⚠️ <strong>This is the riskiest part</strong> — the <code>home</code> object is referenced in many places across the codebase.</p></blockquote><h3 id="phase-c-extract-anime-module-like-fmovies-js-already-does-for-movies" tabindex="-1">Phase C: Extract Anime Module (Like fmovies.js Already Does for Movies) <a class="header-anchor" href="#phase-c-extract-anime-module-like-fmovies-js-already-does-for-movies" aria-label="Permalink to &quot;Phase C: Extract Anime Module (Like fmovies.js Already Does for Movies)&quot;">​</a></h3><p>Right now, <code>19-home.js</code> is a <strong>6,700-line monster</strong> that mixes two very different things:</p><ol><li><strong>App shell logic</strong> — navigation, settings, sidebar, keyboard handling, page switching</li><li><strong>Anime-specific content</strong> — parsing anime data, loading anime homepages, AniList integration, anime schedule</li></ol><p>Meanwhile, <code>21-fmovies.js</code> is a clean, focused file that ONLY handles Movies &amp; TV content. It doesn&#39;t manage navigation or settings — it just provides data when asked.</p><p><strong>The goal:</strong> Make anime work the same way — create a new <code>20-anime-source.js</code> file that only handles anime content, just like <code>21-fmovies.js</code> only handles movies content.</p><h4 id="what-moves-out-of-19-home-js-→-into-20-anime-source-js" tabindex="-1">What Moves OUT of <code>19-home.js</code> → Into <code>20-anime-source.js</code> <a class="header-anchor" href="#what-moves-out-of-19-home-js-→-into-20-anime-source-js" aria-label="Permalink to &quot;What Moves OUT of \`19-home.js\` → Into \`20-anime-source.js\`&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Function/Property</th><th>What It Does</th><th>Why It&#39;s Anime-Specific</th></tr></thead><tbody><tr><td><code>hi_parse()</code></td><td>Parses HTML pages from anime sources into card data</td><td>Only anime sources use HTML scraping</td></tr><tr><td><code>hi_tipurl()</code></td><td>Extracts URL paths from anime source links</td><td>Only used by anime parsers</td></tr><tr><td><code>hi_animeid()</code></td><td>Extracts anime ID from URL</td><td>Only relevant to anime</td></tr><tr><td><code>flix_parse()</code></td><td>Parses FlixHQ-style anime pages</td><td>Anime source specific</td></tr><tr><td><code>recent_parse()</code></td><td>Parses &quot;Recently Updated&quot; anime data</td><td>Anime content</td></tr><tr><td><code>home_anilist_parse()</code></td><td>Parses AniList API responses for anime slideshow</td><td>AniList = anime only</td></tr><tr><td><code>home_anilist_parse_infobox()</code></td><td>Builds anime info cards from AniList data</td><td>AniList = anime only</td></tr><tr><td><code>home_anilist_load()</code></td><td>Loads anime slideshow data from AniList</td><td>AniList = anime only</td></tr><tr><td><code>anilist_trailer_cb()</code></td><td>Handles anime trailer playback</td><td>Anime trailers</td></tr><tr><td><code>anilist_trailer_topcb()</code></td><td>Anime trailer scroll behavior</td><td>Anime trailers</td></tr><tr><td><code>anilist_play_cb()</code></td><td>Plays anime trailer</td><td>Anime trailers</td></tr><tr><td><code>anilist_yt</code></td><td>YouTube trailer state for anime</td><td>Anime trailers</td></tr><tr><td><code>init_homepage()</code> (anime branch)</td><td>Sets up anime homepage sections (trending, popular, etc.)</td><td>The anime content loading</td></tr><tr><td><code>schedule_init()</code> (anime branch)</td><td>Loads anime airing schedule from AniList</td><td>Anime schedule</td></tr></tbody></table><h4 id="what-stays-in-19-home-js-shared-app-shell" tabindex="-1">What STAYS in <code>19-home.js</code> (Shared App Shell) <a class="header-anchor" href="#what-stays-in-19-home-js-shared-app-shell" aria-label="Permalink to &quot;What STAYS in \`19-home.js\` (Shared App Shell)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Function/Property</th><th>What It Does</th><th>Why It&#39;s Shared</th></tr></thead><tbody><tr><td><code>keycb()</code></td><td>Handles d-pad/keyboard navigation</td><td>Works for all modes</td></tr><tr><td><code>update_homepages()</code></td><td>Switches between page tabs</td><td>Works for all modes</td></tr><tr><td><code>header_items</code></td><td>Navigation button references</td><td>Shared header</td></tr><tr><td><code>homepages</code></td><td>Page container references</td><td>Shared layout</td></tr><tr><td><code>menus</code></td><td>Menu item tracking</td><td>Shared navigation</td></tr><tr><td><code>col_selected</code> / <code>row_selected</code></td><td>Current focus position</td><td>Shared navigation</td></tr><tr><td><code>sidebar</code></td><td>Source switching, profiles</td><td>Shared feature</td></tr><tr><td><code>settings</code> / <code>settings_keycb()</code></td><td>App settings</td><td>Shared feature</td></tr><tr><td><code>search</code> / <code>search_keycb()</code></td><td>Search UI</td><td>Both modes use search</td></tr><tr><td><code>init_mylist()</code> / <code>mylist_el</code></td><td>Watchlist/favorites</td><td>Shared feature</td></tr><tr><td><code>recent_init()</code></td><td>Creates a scrollable section row (reusable layout helper)</td><td>Used by both anime and movies</td></tr></tbody></table><h4 id="how-it-would-work-after-extraction" tabindex="-1">How It Would Work After Extraction <a class="header-anchor" href="#how-it-would-work-after-extraction" aria-label="Permalink to &quot;How It Would Work After Extraction&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  19-app-shell.js (formerly 19-home.js)      │</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>│  • Navigation (header, d-pad, page switch)  │</span></span>
<span class="line"><span>│  • Settings                                 │</span></span>
<span class="line"><span>│  • Sidebar                                  │</span></span>
<span class="line"><span>│  • Search UI                                │</span></span>
<span class="line"><span>│  • My List                                  │</span></span>
<span class="line"><span>│  • Shared layout helpers (recent_init, etc) │</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>│  When anime mode → calls anime.init()       │</span></span>
<span class="line"><span>│  When movies mode → calls fmovies.init()    │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span>
<span class="line"><span>         ↓                        ↓</span></span>
<span class="line"><span>┌─────────────────┐    ┌─────────────────────┐</span></span>
<span class="line"><span>│ 20-anime-source │    │ 21-movies-source    │</span></span>
<span class="line"><span>│  (NEW file)     │    │ (formerly fmovies)  │</span></span>
<span class="line"><span>│                 │    │                     │</span></span>
<span class="line"><span>│ • Parse anime   │    │ • TMDB API calls    │</span></span>
<span class="line"><span>│ • AniList API   │    │ • Movie/TV parsing  │</span></span>
<span class="line"><span>│ • Anime slide   │    │ • Movies slideshow  │</span></span>
<span class="line"><span>│ • Anime schedule│    │ • Movies schedule   │</span></span>
<span class="line"><span>│ • Anime homepage│    │ • Movies homepage   │</span></span>
<span class="line"><span>│   sections      │    │   sections          │</span></span>
<span class="line"><span>└─────────────────┘    └─────────────────────┘</span></span></code></pre></div><p>This makes the architecture <strong>symmetrical</strong> — both anime and movies are just &quot;content providers&quot; that plug into the shared app shell. Neither one lives inside the shell&#39;s file.</p><h4 id="why-this-matters-non-technical" tabindex="-1">Why This Matters (Non-Technical) <a class="header-anchor" href="#why-this-matters-non-technical" aria-label="Permalink to &quot;Why This Matters (Non-Technical)&quot;">​</a></h4><p>Think of it like a TV with two channels:</p><ul><li><strong>Right now:</strong> The TV&#39;s remote control code AND the anime channel&#39;s content are crammed into one huge instruction manual. The movies channel has its own clean booklet.</li><li><strong>After refactor:</strong> The remote control has its own manual. Each channel (anime, movies) has its own clean booklet. Much easier to find things and make changes without accidentally breaking something else.</li></ul><hr><h2 id="risk-assessment" tabindex="-1">Risk Assessment <a class="header-anchor" href="#risk-assessment" aria-label="Permalink to &quot;Risk Assessment&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risk</th><th>Level</th><th>Why</th></tr></thead><tbody><tr><td>Breaking CSS styling</td><td>Medium</td><td>Many CSS selectors use <code>#home_header</code></td></tr><tr><td>Breaking JavaScript references</td><td>High</td><td><code>home.home_header</code> and <code>$(&#39;home_header&#39;)</code> appear in many places</td></tr><tr><td>Breaking playback controls</td><td>Medium</td><td>Playback module references <code>home_header</code> for clock visibility</td></tr><tr><td>Build issues</td><td>Low</td><td>Build script just concatenates files — renaming is safe</td></tr></tbody></table><hr><h2 id="recommended-approach" tabindex="-1">Recommended Approach <a class="header-anchor" href="#recommended-approach" aria-label="Permalink to &quot;Recommended Approach&quot;">​</a></h2><ol><li><p><strong>Do Phase A first</strong> — Rename HTML IDs and update all CSS/JS references. This is the most impactful change for readability with manageable risk.</p></li><li><p><strong>Skip Phase B for now</strong> — Renaming the <code>home</code> JavaScript object is high-risk and touches too many places. We can do it later when there&#39;s time for thorough testing.</p></li><li><p><strong>Phase C is a future goal</strong> — Separating anime logic into its own file requires more architectural thought.</p></li></ol><hr><hr><h2 id="implementation-todo-list-by-phase" tabindex="-1">Implementation Todo List (By Phase) <a class="header-anchor" href="#implementation-todo-list-by-phase" aria-label="Permalink to &quot;Implementation Todo List (By Phase)&quot;">​</a></h2><p>Each phase is <strong>independent</strong> — completing one does not require the others. You can do them in any order or skip phases entirely.</p><h3 id="phase-a-rename-html-element-ids-✅-completed-2026-06-23-tested-2026-06-24" tabindex="-1">Phase A: Rename HTML Element IDs ✅ (Completed 2026-06-23, Tested 2026-06-24) <a class="header-anchor" href="#phase-a-rename-html-element-ids-✅-completed-2026-06-23-tested-2026-06-24" aria-label="Permalink to &quot;Phase A: Rename HTML Element IDs ✅ (Completed 2026-06-23, Tested 2026-06-24)&quot;">​</a></h3><ul><li>[x] Audit all <code>home_</code> IDs in <code>main.html</code> and categorize as shared/anime/movies</li><li>[x] Rename shared IDs (<code>home_header</code> → <code>app_header</code>, <code>home_scroll</code> → <code>app_scroll</code>, etc.)</li><li>[x] Rename anime-specific IDs (<code>home_schedule</code> → <code>anime_nav_schedule</code>, <code>home_pageschedule</code> → <code>anime_page_schedule</code>)</li><li>[x] Rename movies-specific IDs (<code>home_movies</code> → <code>movies_nav_movies</code>, <code>home_pagemovies</code> → <code>movies_page_movies</code>, etc.)</li><li>[x] Update all CSS files that reference old IDs (<code>fp.css</code>, <code>p.css</code>, <code>fm.css</code>, <code>m.css</code>)</li><li>[x] Update all JS files that reference old IDs via <code>$(&#39;...&#39;)</code> calls (<code>19-home.js</code>, <code>18-playback.js</code>, <code>21-fmovies.js</code>)</li><li>[x] Build and verify: <code>npm run build:webview</code></li><li>[x] Test anime mode (navigation, slideshow, settings, clock)</li><li>[x] Test movies mode (tabs, content loading, search)</li><li>[x] Test playback (clock hide/show)</li></ul><h3 id="phase-b-rename-the-javascript-object-✅-completed-tested-2026-06-24" tabindex="-1">Phase B: Rename the JavaScript Object ✅ (Completed &amp; Tested 2026-06-24) <a class="header-anchor" href="#phase-b-rename-the-javascript-object-✅-completed-tested-2026-06-24" aria-label="Permalink to &quot;Phase B: Rename the JavaScript Object ✅ (Completed &amp; Tested 2026-06-24)&quot;">​</a></h3><ul><li>[x] Rename <code>id=&quot;home&quot;</code> DOM element → <code>id=&quot;app_shell&quot;</code> (HTML, CSS, JS)</li><li>[x] Rename <code>const home = {...}</code> → <code>const app = {...}</code></li><li>[x] Find/replace all <code>home.</code> references across all modules (with negative lookbehind to protect property accesses like <code>listOrder.home</code>)</li><li>[x] Update property names (<code>home.home_header</code> → <code>app.header</code>, <code>home.home_scroll</code> → <code>app.scroll</code>, <code>home.home_slide</code> → <code>app.slideshow</code>, etc.)</li><li>[x] Rename <code>home.home</code> (DOM element property) → <code>app.el</code></li><li>[x] Build and verify: <code>npm run build:webview</code></li><li>[x] Test anime mode</li><li>[x] Test movies mode</li><li>[x] Test playback</li></ul><h3 id="phase-c-extract-anime-logic-into-separate-module-✅-completed-2026-06-24" tabindex="-1">Phase C: Extract Anime Logic into Separate Module ✅ (Completed 2026-06-24) <a class="header-anchor" href="#phase-c-extract-anime-logic-into-separate-module-✅-completed-2026-06-24" aria-label="Permalink to &quot;Phase C: Extract Anime Logic into Separate Module ✅ (Completed 2026-06-24)&quot;">​</a></h3><ul><li>[x] Create new file <code>20-anime-source.js</code></li><li>[x] Move <code>hi_parse()</code>, <code>hi_tipurl()</code>, <code>hi_animeid()</code> into new file (as <code>anime.hiParse</code>, <code>anime.tipurl</code>, <code>anime.animeid</code>)</li><li>[x] Move <code>flix_parse()</code>, <code>recent_parse()</code> into new file (as <code>anime.flixParse</code>, <code>anime.recentParse</code>)</li><li>[x] Move anime homepage sections builder into new file (as <code>anime.getHomepageSections()</code>)</li><li>[x] Keep <code>anilist_yt</code>, trailer callbacks, <code>anilistParse</code>, <code>anilistLoad</code> in app shell (shared slideshow feature used by multiple modes via AniList integration)</li><li>[x] Keep <code>schedule_init()</code> in app shell (routes between fmovies and anime schedule)</li><li>[x] Update <code>19-home.js</code> — <code>hi_parse</code>, <code>flix_parse</code>, <code>recent_parse</code> now delegate to <code>anime.*</code> methods</li><li>[x] <code>init_homepage()</code> already calls <code>anime.getHomepageSections()</code> for anime content sections</li><li>[x] Register new file in <code>scripts/build-webview.js</code> build order (after 19, before 21)</li><li>[x] Build and verify: <code>npm run build:webview</code> — success</li><li>[x] Test anime mode thoroughly (all homepage sections, slideshow, schedule, trailers)</li><li>[x] Test movies mode (should be unaffected)</li></ul><h3 id="phase-d-rename-file-names-✅-completed-2026-06-24" tabindex="-1">Phase D: Rename File Names ✅ (Completed 2026-06-24) <a class="header-anchor" href="#phase-d-rename-file-names-✅-completed-2026-06-24" aria-label="Permalink to &quot;Phase D: Rename File Names ✅ (Completed 2026-06-24)&quot;">​</a></h3><ul><li>[x] Rename <code>19-home.js</code> → <code>19-app-shell.js</code></li><li>[x] Rename <code>21-fmovies.js</code> → <code>21-movies-source.js</code></li><li>[x] Update <code>scripts/build-webview.js</code> to reference new filenames</li><li>[x] Build and verify: <code>npm run build:webview</code></li><li>[x] Verify no broken references</li></ul><hr><h2 id="how-to-validate" tabindex="-1">How To Validate <a class="header-anchor" href="#how-to-validate" aria-label="Permalink to &quot;How To Validate&quot;">​</a></h2><p>After each phase:</p><ol><li>Run <code>npm run build:webview</code> — must succeed</li><li>Test anime mode — navigation, slideshow, settings, clock all work</li><li>Test Movies &amp; TV mode — all tabs, content loading, search work</li><li>Test playback — clock hide/show still works during video</li></ol><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The core issue is that <code>home_header</code> sounds like it belongs to the &quot;Home page&quot; or the anime home, but it&#39;s actually the <strong>app-wide navigation bar shared by everything</strong>. Renaming it to <code>app_header</code> makes it immediately clear that it&#39;s a shared skeleton piece, not tied to any specific content mode.</p><p>The same logic applies throughout: anything shared should say &quot;app_&quot;, anything anime-only should say &quot;anime_&quot;, and anything movies-only should say &quot;movies_&quot;.</p>`,79)])])}const u=t(s,[["render",i]]);export{p as __pageData,u as default};
